const today = new Date();

function parseThaiDate(dateStr){
  if(!dateStr) return null;
  const [day,month,year] = dateStr.split("/");
  return new Date(`${year}-${month}-${day}`);
}

return items.map(item => {

  const dueDate = parseThaiDate(item.json["วันครบกำหนดชำระ"]);
  const contractEnd = parseThaiDate(item.json["วันหมดสัญญา"]);

  const daysUntilDue = Math.ceil((dueDate - today) / (1000*60*60*24));
  const daysOverdue = daysUntilDue < 0 ? Math.abs(daysUntilDue) : 0;
  const contractDaysRemaining = Math.ceil((contractEnd - today) / (1000*60*60*24));

  let riskLevel = "ต่ำ";
  if (daysOverdue > 7) riskLevel = "สูง";
  else if (daysOverdue > 0) riskLevel = "กลาง";

  return {
    json: {
      ...item.json,
      daysUntilDue,
      daysOverdue,
      contractDaysRemaining,
      riskLevel
    }
  };
});

return items.map(item => {
  let message = "";

  const daysUntilDue = item.json.daysUntilDue ?? 0;
  const daysOverdue = item.json.daysOverdue ?? 0;

  if (daysUntilDue > 0) {
    message = `📢 แจ้งเตือนค่าเช่า

ห้อง: ${item.json["ห้อง"]}
ผู้เช่า: ${item.json["ชื่อผู้เช่า"]}
ค่าเช่า: ${item.json["ค่าเช่ารายเดือน"]}

จะครบกำหนดใน ${daysUntilDue} วัน
กรุณาชำระก่อนกำหนด`;
  } 
  else if (daysOverdue > 0 && daysOverdue <= 3) {
    message = `⏰ แจ้งเตือน

ค่าเช่าห้อง ${item.json["ห้อง"]} เกินกำหนด ${daysOverdue} วัน
กรุณาชำระโดยเร็ว`;
  } 
  else if (daysOverdue > 3) {
    message = `⚠️ แจ้งเตือนด่วน

ห้อง ${item.json["ห้อง"]} ค้างชำระ ${daysOverdue} วัน
กรุณาติดต่อผู้ดูแลทันที`;
  } 
  else {
    message = `📌 แจ้งเตือนค่าเช่าห้อง

ห้อง: ${item.json["ห้อง"]}
ผู้เช่า: ${item.json["ชื่อผู้เช่า"]}

โปรดตรวจสอบสถานะการชำระเงิน`;
  }

  return {
    json: {
      ...item.json,
      reminderMessage: message
    }
  };
});

return items.map(item => {

  const room = item.json["ห้อง"];
  const tenant = item.json["ชื่อผู้เช่า"];
  const endDate = item.json["วันหมดสัญญา"];
  const daysLeft = item.json.contractDaysRemaining;

  const renewalMessage =
`📄 แจ้งเตือนการต่อสัญญาเช่า

ห้อง: ${room}
ผู้เช่า: ${tenant}

สัญญาเช่าจะหมดวันที่ ${endDate}
เหลือเวลาอีก ${daysLeft} วัน

กรุณาติดต่อเพื่อดำเนินการต่อสัญญา
ขอบคุณครับ`;

  return {
    json: {
      ...item.json,
      renewalMessage
    }
  };
});

const rows = $input.all();

if (!rows || rows.length === 0) {
  return [{
    json: {
      totalIssues: 0,
      topCategory: "-",
      topCategoryCount: 0,
      topRoom: "-",
      topRoomCount: 0
    }
  }];
}

let categoryCount = {};
let roomCount = {};

for (const item of rows) {

  const category = item.json["ประเภทปัญหา"];
  const room = item.json["ห้อง"];

  if (category) {
    categoryCount[category] = (categoryCount[category] || 0) + 1;
  }

  if (room) {
    roomCount[room] = (roomCount[room] || 0) + 1;
  }

}

function findTop(data){

  let max = 0;
  let key = "-";

  for (const k in data) {
    if (data[k] > max) {
      max = data[k];
      key = k;
    }
  }

  return { key, max };
}

const topCategory = findTop(categoryCount);
const topRoom = findTop(roomCount);

return [{
  json:{
    totalIssues: rows.length,
    topCategory: topCategory.key,
    topCategoryCount: topCategory.max,
    topRoom: topRoom.key,
    topRoomCount: topRoom.max
  }
}];

